def _parse_button(name):
    try:
        return getattr(mouse.Button, name)
    except Exception:
        return mouse.Button.left

def _parse_key(value):
    if not value:
        return None
    if isinstance(value, str) and value.startswith('Key.'):
        name = value.split('.', 1)[1]
        return getattr(keyboard.Key, name, value)
    return value

def play():
    m = mouse.Controller()
    k = keyboard.Controller()
    last = 0.0
    for t, kind, data in events:
        wait = t - last
        if wait > 0:
            time.sleep(wait)
        last = t
        if kind == 'move':
            m.position = (data['x'], data['y'])
        elif kind == 'click':
            m.position = (data['x'], data['y'])
            btn = _parse_button(data['button'])
            if data['pressed']:
                m.press(btn)
            else:
                m.release(btn)
        elif kind == 'scroll':
            m.position = (data['x'], data['y'])
            m.scroll(data['dx'], data['dy'])
        elif kind == 'key_down':
            key = _parse_key(data.get('key'))
            if key is not None:
                k.press(key)
        elif kind == 'key_up':
            key = _parse_key(data.get('key'))
            if key is not None:
                k.release(key)

if __name__ == '__main__':
    play()
